#include<stdio.h>
int main()
{
	int n, k;
	int i, s = 0, a[101];
	while (scanf("%d%d", &n, &k) != EOF)
	{
		for (i = 1; i <= n; i++)
			scanf("%d", &a[i]);
		for (i = 1; i <= n; i++)
		{
			if (a[i] >= a[k] && a[i] != 0)
				s++;
		}
		printf("%d\n", s);
	}
	return 0;
}

